module RefModule(
    input                 clk,
    input                 rst_n,

    output reg  [2:0]     count
);

// Ring counter implementation
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst_n or posedge dbg_halt) begin
    if (!rst_n)
        count <= 3'b001;
    else
        count <= {count[1:0], count[2]};
end

endmodule
